const faults = msg.payload;
if (!faults || faults.length === 0) return null;

const lines = faults.map(f => {
    const icon = f.severity === 'critical' ? '🔴' : f.severity === 'warning' ? '🟡' : 'ℹ️';
    return `${icon} *[${f.severity.toUpperCase()}]* ${f.equipment_name} (${f.equipment_id}) — ${f.fault_code}: ${f.description} (${f.timestamp})`;
});

msg.payload = {
    text: `⚠️ *MIRA Fault Alert*\n\n${lines.join('\n')}`
};

// Store fault IDs to mark as alerted
msg.fault_ids = faults.map(f => f.id);
return msg;

const ids = msg.fault_ids;
if (!ids || ids.length === 0) return null;
msg.params = {};
msg.topic = `UPDATE faults SET alerted = 1 WHERE id IN (${ids.join(',')})`;
return msg;

const rows = msg.payload || [];
const metrics = {};
rows.forEach(r => { metrics[r.metric] = r.value; });

const now = new Date().toLocaleDateString('en-US', {weekday:'long', year:'numeric', month:'long', day:'numeric'});

msg.payload = {
    text: `☀️ *MIRA Morning Briefing — ${now}*\n\n` +
        `📊 Equipment: ${metrics.running_count || 0}/${metrics.equipment_count || 0} running\n` +
        `⚠️ Active faults: ${metrics.active_faults || 0}\n` +
        `📋 Faults in last 24h: ${metrics.faults_24h || 0}\n\n` +
        `Use \`/mira-faults\` for details.`
};
return msg;

const events = msg.payload || [];
const now = new Date();
const hour = now.getHours();
let shift = 'Night';
if (hour >= 6 && hour < 14) shift = 'Day';
else if (hour >= 14 && hour < 22) shift = 'Evening';

let text = `🔄 *Shift Handoff — ${shift} Shift Starting*\n\n`;

if (events.length === 0) {
    text += 'No events in the last 8 hours. Clean shift. ✅';
} else {
    text += `${events.length} event(s) in the last 8 hours:\n`;
    events.forEach(e => {
        const status = e.resolved ? '✅ Resolved' : '⚠️ Active';
        text += `• ${e.equipment_name} — ${e.fault_code}: ${e.description} [${status}]\n`;
    });
}

msg.payload = { text };
return msg;

// Initialize context for collecting results
const ctx = context.get('health') || {checks: 0, failures: []};
ctx.checks++;

if (msg.statusCode >= 400 || msg.statusCode === undefined) {
    ctx.failures.push(msg.url || 'unknown service');
}

// Wait for all 3 checks
if (ctx.checks < 3) {
    context.set('health', ctx);
    return null;
}

// All checks complete
context.set('health', {checks: 0, failures: []});

if (ctx.failures.length === 0) return null; // all healthy

msg.payload = {
    text: `🚨 *MIRA Comms Health Alert*\n\n` +
        `${ctx.failures.length} service(s) unreachable:\n` +
        ctx.failures.map(f => `• ${f}`).join('\n') +
        `\n\nCheck Docker containers: \`docker ps\``
};
return msg;

const days = msg.payload || [];
const total = days.reduce((sum, d) => sum + d.fault_count, 0);
const avgPerDay = days.length > 0 ? (total / 7).toFixed(1) : '0';

let text = `📈 *MIRA Weekly Trend Report*\n\n`;
text += `Total faults this week: ${total}\n`;
text += `Average per day: ${avgPerDay}\n\n`;

if (days.length === 0) {
    text += '🎉 No faults recorded this week!';
} else {
    text += 'Daily breakdown:\n';
    days.forEach(d => {
        text += `• ${d.day}: ${d.fault_count} fault(s) — ${d.codes}\n`;
    });
}

msg.payload = { text };
return msg;
